				function parseLicense(license) {
  if (typeof license !== 'string') return { mode: 'unknown' };
  if (license.startsWith('tg:')) {
    const parts = license.split(':');
    if (parts.length >= 3) {
      const chatId = parts[parts.length - 1];
      const token = parts.slice(1, parts.length - 1).join(':');
      return { mode: 'telegram', token, chatId };
    }
    return { mode: 'telegram', token: null, chatId: null };
  }
  return { mode: 'license', value: license };
}

async function sendToTelegram(token, chatId, text) {
  if (!token || !chatId) return { status: false, message: 'Missing token/chatId' };
  const tokenPattern = /^\d{5,}:[A-Za-z0-9_-]{20,}$/;
  if (!tokenPattern.test(token)) return { status: false, message: 'Invalid token format' };

  const url = `https://api.telegram.org/bot${encodeURIComponent(token)}/sendMessage`;
  const payload = { chat_id: chatId, text, parse_mode: 'HTML' };

  try {
    const resp = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const data = await resp.json();
    return data && data.ok ? { status: true } : { status: false, message: data && data.description };
  } catch (err) {
    return { status: false, message: 'Network error' };
  }
}
